        $builder->startVector(1, count($data), 1);
        for ($i = count($data) - 1; $i >= 0; $i--) {
            $builder->putByte($data[$i]);
        }
        return $builder->endVector();
    }

    /**
     * @param FlatBufferBuilder $builder
     * @param int $numElems
     * @return void
     */
    public static function startPROVIDER_SIGNATUREVector(FlatBufferBuilder $builder, $numElems)
    {
        $builder->startVector(1, $numElems, 1);
    }

    /**
     * @param FlatBufferBuilder $builder
     * @return int table offset
     */
    public static function endPUR(FlatBufferBuilder $builder)
    {
        $o = $builder->endObject();
        $builder->required($o, 4);  // REQUEST_ID
        $builder->required($o, 6);  // LISTING_ID
        $builder->required($o, 8);  // TIER_NAME
        $builder->required($o, 10);  // BUYER_PEER_ID
        return $o;
    }

    public static function finishPURBuffer(FlatBufferBuilder $builder, $offset)
    {
        $builder->finish($offset, "$PUR");
    }
}
